const RELOAD_KEY = '_mf_deploy_reload_ts';
const RELOAD_WINDOW_MS = 30 * 60 * 1000;  // 30 minutes
const MAX_RELOADS_IN_WINDOW = 3;

/** Errors typical when static assets 404 or HTML is served during a deploy window. */
export function isDeployRelatedLoadError(error: unknown): boolean {
  const errStr = String(error);
  return (
    errStr.includes('__SECRET_INTERNALS_DO_NOT_USE_OR_YOU_WILL_BE_FIRED') ||
    errStr.includes('Failed to fetch') ||
    errStr.includes('NetworkError') ||
    errStr.includes('Unexpected token') ||
    /Error loading .*? from /.test(errStr) ||
    (/404/.test(errStr) && /\.js/i.test(errStr))
  );
}

/**
 * Hard reload with time-windowed cap.
 *
 * Tracks reload timestamps in sessionStorage with a sliding window of 30 min.
 * Unlike the old fixed 2-reload session cap, this resets automatically after
 * the window elapses, so a user who returns hours later gets fresh reload attempts.
 */
export function scheduleDeployReload(reason: string, delayMs = 3000): boolean {
  const now = Date.now();
  const raw = sessionStorage.getItem(RELOAD_KEY);
  const timestamps: number[] = raw ? JSON.parse(raw) : [];
  const recent = timestamps.filter((t) => now - t < RELOAD_WINDOW_MS);

  if (recent.length >= MAX_RELOADS_IN_WINDOW) {
    console.warn(
      `[DeployRecovery] Reload cap (${MAX_RELOADS_IN_WINDOW} within ${RELOAD_WINDOW_MS / 60000}min) — waiting for window to expire`,
    );
    return false;
  }

  recent.push(now);
  sessionStorage.setItem(RELOAD_KEY, JSON.stringify(recent));

  console.warn(
    `[DeployRecovery] ${reason} — reloading in ${delayMs}ms (${recent.length}/${MAX_RELOADS_IN_WINDOW} within 30min window)`,
  );
  setTimeout(() => window.location.reload(), delayMs);
  return true;
}

export function resetDeployReloadCounter(): void {
  sessionStorage.removeItem(RELOAD_KEY);
}
