/**
 * SSOT: @linm-soft-org/linm-web-common-components/src/utils/authRefreshUrl.ts
 * Root bundles this copy — keep in sync on common-components publish.
 *
 * Production: deploy workflow maps vars.VITE_*_API_URL → build VITE_AUTH_BFF_URL → __LINM_AUTH_BFF_URL__.
 */
declare const __LINM_AUTH_BFF_URL__: string | undefined;

declare global {
  interface Window {
    __LINM_AUTH_BFF_BASE__?: string;
  }
}

function isLocalDevOrigin(): boolean {
  return (
    typeof window !== 'undefined'
    && /localhost|127\.0\.0\.1/.test(window.location.origin)
  );
}

function normalizeBase(base: string): string {
  return base.trim().replace(/\/$/, '');
}

function isValidAuthBffBase(base: string, localDev: boolean): boolean {
  try {
    const u = new URL(base);
    if (u.protocol !== 'https:' && u.protocol !== 'http:') return false;
    if (!localDev) {
      if (u.protocol !== 'https:') return false;
      if (/localhost|127\.0\.0\.1/i.test(u.hostname)) return false;
    }
    const path = u.pathname.replace(/\/$/, '');
    return path.endsWith('/web-bff/api/v1');
  } catch {
    return false;
  }
}

function resolveAuthBffBase(): string | null {
  const localDev = isLocalDevOrigin();

  const fromWindow =
    typeof window !== 'undefined' ? window.__LINM_AUTH_BFF_BASE__ : undefined;
  const fromBuild =
    typeof __LINM_AUTH_BFF_URL__ !== 'undefined' ? __LINM_AUTH_BFF_URL__ : undefined;

  for (const candidate of [fromWindow, fromBuild]) {
    if (!candidate?.trim()) continue;
    const base = normalizeBase(candidate);
    if (isValidAuthBffBase(base, localDev)) return base;
    console.error('[auth] Invalid auth BFF base — fix API URL repo variable on Linm.Web.Root deploy');
  }

  if (localDev) {
    return 'http://localhost:5010/web-bff/api/v1';
  }

  console.error(
    '[auth] Missing auth BFF URL — set vars.VITE_BV_API_URL / VITE_ERP_API_URL on Linm.Web.Root and redeploy',
  );
  return null;
}

export function resolveAuthRefreshUrl(): string {
  const base = resolveAuthBffBase();
  if (base) {
    return `${base}/auth/refresh-token`;
  }
  if (isLocalDevOrigin()) {
    return 'http://localhost:5010/web-bff/api/v1/auth/refresh-token';
  }
  return '/web-bff/api/v1/auth/refresh-token';
}
