import { resolveAuthRefreshUrl } from './authRefreshUrl';
import { clearActiveCompanyCode, getActiveCompanyCode } from './activeCompanyStorage';
import { clearAuthTokens, getAuthRefreshToken, getAuthToken, setAuthTokens } from '../storage/authTokenStorage';
import { clearAuthUser, getAuthUser, setAuthUser, type StoredAuthUser } from '../storage/authUserStorage';
import { X_COMPANY_ID_HEADER } from './companyRequestHeaders';

export const AUTH_FETCH_SKIP_REFRESH_HEADER = 'X-Linm-Skip-Auth-Refresh';

let refreshPromise: Promise<boolean> | null = null;
let nativeFetch: typeof fetch | null = null;

export function setAuthRefreshNativeFetch(fetchFn: typeof fetch): void {
  nativeFetch = fetchFn;
}

function getFetch(): typeof fetch {
  return nativeFetch ?? fetch;
}

/** Extract access token from Auth login/refresh JSON (camelCase or PascalCase). */
export function parseAccessTokenFromAuthResponse(data: Record<string, unknown>): string | null {
  const raw =
    data.token ?? data.accessToken ?? data.AccessToken ?? data.Token;
  if (typeof raw !== 'string') return null;
  const trimmed = raw.trim();
  return trimmed.length > 0 ? trimmed : null;
}

/** Extract refresh token from Auth login/refresh JSON. */
export function parseRefreshTokenFromAuthResponse(data: Record<string, unknown>): string | null {
  const raw = data.refreshToken ?? data.RefreshToken;
  if (typeof raw !== 'string') return null;
  const trimmed = raw.trim();
  return trimmed.length >= 32 ? trimmed : null;
}

const AUTH_SELF_SEGMENTS = ['/auth/login', '/auth/logout', '/auth/refresh-token'];

export function isAuthSelfRequestUrl(url: string): boolean {
  try {
    const path = new URL(url, typeof window !== 'undefined' ? window.location.origin : 'http://localhost').pathname;
    return AUTH_SELF_SEGMENTS.some((segment) => path.includes(segment));
  } catch {
    return false;
  }
}

export function requestHadBearerAuth(input: RequestInfo | URL, init?: RequestInit): boolean {
  if (init?.headers) {
    const auth = new Headers(init.headers).get('Authorization');
    if (auth?.startsWith('Bearer ')) return true;
  }
  if (input instanceof Request) {
    const auth = input.headers.get('Authorization');
    if (auth?.startsWith('Bearer ')) return true;
  }
  return false;
}

export function tryRefreshToken(): Promise<boolean> {
  if (refreshPromise) return refreshPromise;

  refreshPromise = (async () => {
    const rt = getAuthRefreshToken();
    if (!rt) return false;

    try {
      const res = await getFetch()(resolveAuthRefreshUrl(), {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          [AUTH_FETCH_SKIP_REFRESH_HEADER]: '1',
        },
        body: JSON.stringify({ refreshToken: rt }),
      });

      if (!res.ok) return false;

      const data = (await res.json()) as Record<string, unknown>;
      const accessToken = parseAccessTokenFromAuthResponse(data);
      if (!accessToken) {
        console.error('[auth] Refresh response missing access token');
        return false;
      }

      const prevAccess = getAuthToken();
      setAuthTokens({
        accessToken,
        refreshToken: parseRefreshTokenFromAuthResponse(data) ?? undefined,
      });

      if (data.user) {
        const prev = getAuthUser();
        const nextUser = data.user as StoredAuthUser;
        if (JSON.stringify(prev) !== JSON.stringify(nextUser)) {
          setAuthUser(nextUser);
        }
      }

      return getAuthToken() !== prevAccess;
    } catch {
      return false;
    } finally {
      refreshPromise = null;
    }
  })();

  return refreshPromise;
}

/**
 * Redirect after an auth failure (expired/revoked token mid-session).
 *
 * - If the user previously had a token, redirect to /session-expired
 *   so Home MFE shows the "Phiên đăng nhập hết hạn" page (distinct from
 *   a cold start where the user has never logged in).
 * - If there was already no token, redirect to /login.
 */
export function redirectToLoginAfterAuthFailure(): void {
  clearAuthTokens();
  clearAuthUser();
  clearActiveCompanyCode();
  window.location.href = '/session-expired';
}

export function buildRetryRequestInit(
  input: RequestInfo | URL,
  init: RequestInit | undefined,
  newToken: string,
): RequestInit | undefined {
  if (input instanceof Request) {
    const headers = new Headers(input.headers);
    if (init?.headers) {
      new Headers(init.headers).forEach((value, key) => headers.set(key, value));
    }
    headers.set('Authorization', `Bearer ${newToken}`);
    const activeCompanyCode = getActiveCompanyCode();
    if (activeCompanyCode) headers.set(X_COMPANY_ID_HEADER, activeCompanyCode);
    return { ...init, headers };
  }

  const headers = new Headers(init?.headers);
  headers.set('Authorization', `Bearer ${newToken}`);
  const activeCompanyCode = getActiveCompanyCode();
  if (activeCompanyCode) headers.set(X_COMPANY_ID_HEADER, activeCompanyCode);
  return { ...init, headers };
}

export function getAuthTokenForRetry(): string | null {
  return getAuthToken();
}
