const style = document.createElement('style');
style.setAttribute('data-linm-css', 'root');
style.innerHTML = `
  * { box-sizing: border-box; }
  body { margin: 0; padding: 0; font-family: 'Roboto', sans-serif; }
  #app-root { display: flex; flex-direction: column; min-height: 100vh; }
  #navigation { position: sticky; top: 0; z-index: 1000; background: #fff; }
  #main-content {
    flex: 1;
    min-height: 0;
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }
  .root-loader {
    position: fixed; inset: 0; display: flex;
    align-items: center; justify-content: center;
    background: #fff; z-index: 9999;
  }
  .root-loader__spinner {
    width: 48px; height: 48px;
    border: 4px solid #e0e0e0; border-top-color: #1976d2;
    border-radius: 50%; animation: spin 0.8s linear infinite;
  }
  @keyframes spin { to { transform: rotate(360deg); } }

  /* Navigation transition overlay — covers the unmount/mount gap between apps */
  #spa-nav-overlay {
    position: fixed; inset: 0;
    background: rgba(255, 255, 255, 0.45);
    z-index: 9998;
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.12s ease;
  }
  #spa-nav-overlay.visible { opacity: 1; }

  /* Permission bootstrap — full page until @linm/nav resolves menu/allow-list */
  #linm-perm-bootstrap {
    position: fixed; inset: 0;
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    gap: 16px;
    background: #fff;
    z-index: 10000;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.15s ease;
  }
  #linm-perm-bootstrap.visible {
    opacity: 1;
    pointer-events: auto;
  }
  .linm-perm-bootstrap__stage {
    perspective: 520px;
    width: 80px; height: 80px;
    display: flex; align-items: center; justify-content: center;
  }
  .linm-perm-bootstrap__logo {
    width: 64px; height: 64px;
    object-fit: contain;
    transform-style: preserve-3d;
    backface-visibility: visible;
    animation: linm-logo-3d-spin 1.8s linear infinite;
    will-change: transform;
  }
  @keyframes linm-logo-3d-spin {
    from { transform: rotateY(0deg); }
    to { transform: rotateY(360deg); }
  }
  .linm-perm-bootstrap__label {
    margin: 0;
    color: #666;
    font-size: 14px;
    letter-spacing: 0.02em;
    font-family: 'Roboto', sans-serif;
    animation: linm-loading-pulse 1.6s ease-in-out infinite;
  }
  @keyframes linm-loading-pulse {
    0%, 100% { opacity: 0.5; }
    50% { opacity: 1; }
  }
`;
document.head.appendChild(style);
