import { hasValidAuthToken } from '../storage/authTokenStorage';

const PERMISSION_LOADING = 'linm:permission:loading';
const PERMISSION_READY = 'linm:permission:ready';
/** Fail-safe — unblock if @linm/nav never signals ready (nav error, API 503 hang). */
const BOOTSTRAP_MAX_MS = 25_000;

const PUBLIC_PATHS = [
  '/login',
  '/logout',
  '/session-expired',
  '/oidc-callback',
  '/oidc-silent-renew',
  '/unauthorized',
];

/** Shell-embed routes (ShellUrl standalone FAB) — no nav/permissions needed. */
const SHELL_EMBED_PREFIXES = ['/shell-url', '/shell'];

function normalizePath(pathname: string): string {
  if (!pathname || pathname === '/') return pathname || '/';
  return pathname.endsWith('/') ? pathname.slice(0, -1) : pathname;
}

function isPublicPath(pathname: string): boolean {
  const normalized = normalizePath(pathname);
  return PUBLIC_PATHS.some(
    (p) => normalized === p || normalized.startsWith(`${p}/`),
  );
}

function isShellEmbedPath(pathname: string): boolean {
  const n = normalizePath(pathname);
  return SHELL_EMBED_PREFIXES.some(
    (p) => n === p || n.startsWith(`${p}/`),
  );
}

function shouldGatePermissions(pathname: string): boolean {
  return hasValidAuthToken() && !isPublicPath(pathname) && !isShellEmbedPath(pathname);
}

/**
 * Full-page spinner only on cold permission bootstrap (first menu load).
 * After menu ready, route refresh uses @linm/nav main-content skeleton only.
 */
export function setupPermissionsBootstrap(): void {
  let overlay = document.getElementById('linm-perm-bootstrap');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'linm-perm-bootstrap';
    overlay.setAttribute('role', 'status');
    overlay.setAttribute('aria-live', 'polite');
    overlay.setAttribute('aria-busy', 'true');
    overlay.innerHTML = `
      <div class="linm-perm-bootstrap__stage" aria-hidden="true">
        <img class="linm-perm-bootstrap__logo" src="/icons/logo.svg" alt="" width="64" height="64" />
      </div>
      <p class="linm-perm-bootstrap__label">Đang tải hệ thống…</p>
    `;
    document.body.appendChild(overlay);
  }

  let busy = false;
  let ready = false;
  /** After first PERMISSION_READY, route refresh uses main-area skeleton only. */
  let menuEverReady = false;
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  const clearBootstrapTimeout = () => {
    if (timeoutId != null) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
  };

  const sync = () => {
    const gate = shouldGatePermissions(window.location.pathname);
    const show = gate && (busy || !ready);
    overlay!.classList.toggle('visible', show);
    overlay!.setAttribute('aria-busy', show ? 'true' : 'false');
    if (!show) clearBootstrapTimeout();
  };

  const unblock = () => {
    busy = false;
    ready = true;
    clearBootstrapTimeout();
    sync();
  };

  const armBootstrapTimeout = () => {
    clearBootstrapTimeout();
    if (!shouldGatePermissions(window.location.pathname)) return;
    timeoutId = setTimeout(unblock, BOOTSTRAP_MAX_MS);
  };

  const onLoading = () => {
    if (menuEverReady) return;
    busy = true;
    ready = false;
    armBootstrapTimeout();
    sync();
  };

  const onReady = () => {
    menuEverReady = true;
    unblock();
  };

  const onAuthChange = () => {
    if (!hasValidAuthToken()) {
      menuEverReady = false;
    }
    busy = false;
    ready = menuEverReady;
    if (shouldGatePermissions(window.location.pathname) && !menuEverReady) {
      busy = true;
      ready = false;
      armBootstrapTimeout();
    } else {
      clearBootstrapTimeout();
    }
    sync();
  };

  window.addEventListener(PERMISSION_LOADING, onLoading);
  window.addEventListener(PERMISSION_READY, onReady);
  window.addEventListener('linm:auth:token-changed', onAuthChange);
  window.addEventListener('linm:auth:changed', onAuthChange);
  window.addEventListener('linm:company:changed', onAuthChange);
  window.addEventListener('single-spa:routing-event', () => {
    if (shouldGatePermissions(window.location.pathname) && (busy || !ready)) {
      armBootstrapTimeout();
    }
    sync();
  });

  if (shouldGatePermissions(window.location.pathname)) {
    busy = true;
    ready = false;
    armBootstrapTimeout();
  }
  sync();
}
