import { getSecureItem, removeSecureItem, setSecureItem, type SecureStorageConfig } from './secureStorage';

export const AUTH_USER_STORAGE_KEY = 'auth_user';

/** JWT-mode user snapshot persisted by Web.Home authSlice. */
export interface StoredAuthUser {
  id?: string;
  username?: string;
  email?: string;
  role?: string;
  roles?: string[];
  companyCode?: string;
  companyName?: string;
  fullName?: string;
  package?: string;
  [key: string]: unknown;
}

const AUTH_USER_CONFIG: SecureStorageConfig = {
  storageKey: AUTH_USER_STORAGE_KEY,
  version: 1,
  hashKey: 'auth.user',
};

function parseLegacyAuthUser(raw: string): StoredAuthUser | null {
  try {
    const parsed = JSON.parse(raw) as StoredAuthUser;
    if (parsed && typeof parsed === 'object' && typeof parsed.id === 'string') {
      return parsed;
    }
  } catch {
    // ignore
  }
  return null;
}

export function getAuthUser(): StoredAuthUser | null {
  return getSecureItem<StoredAuthUser>(AUTH_USER_CONFIG, {
    allowLegacyPlain: true,
    legacyParse: parseLegacyAuthUser,
  });
}

export function setAuthUser(user: StoredAuthUser): void {
  setSecureItem(AUTH_USER_CONFIG, user);
  window.dispatchEvent(new CustomEvent('linm:auth:changed'));
}

export function clearAuthUser(): void {
  removeSecureItem(AUTH_USER_CONFIG);
  window.dispatchEvent(new CustomEvent('linm:auth:changed'));
}
