import { Authenticator } from './libs/authentication/authenticator';
import OpenIdSettings, { OidcEndpoints } from './libs/authentication/openIdSettings';
import { bootstrap } from './libs/startup/bootstrap';
import { AppSettings } from './libs/configuration/appsettings';
import { clearAuthTokens } from './libs/storage/authTokenStorage';
import { clearAuthUser } from './libs/storage/authUserStorage';
import { start } from 'single-spa';
import { logError, logInfo } from './logger';
import {
  broadcastLogoutToOtherTabs,
  initializeCrossTabLogout,
} from './libs/logout/cross-tab-logout';
import { installAuthFetchInterceptor } from './libs/auth/authFetchInterceptor';
import './styles';

declare global {
  interface Window {
    __LINM_ENABLE_MESSAGE__?: boolean;
    __LINM_ENABLE_NOTIFICATION__?: boolean;
  }
}

// Expose before any MFE chunk evaluates topbar flags.
window.__LINM_ENABLE_MESSAGE__ = AppSettings.ENABLE_MESSAGE;
window.__LINM_ENABLE_NOTIFICATION__ = AppSettings.ENABLE_NOTIFICATION;

window.addEventListener('unhandledrejection', (event) => {
  logError(`[Unhandled Rejection] ${event.reason}`);
});

initializeCrossTabLogout();

// JWT mode: patch fetch once before any MFE loads (Nav permissions, Home login, ERP API).
if (!AppSettings.OIDC_ENABLED) {
  installAuthFetchInterceptor();
  logInfo('[Auth] Global fetch interceptor installed (JWT refresh)');
}

const authenticator = Authenticator.getInstance(OpenIdSettings);

const path = window.location.pathname.substring(1);

try {
  switch (path) {
    case OidcEndpoints.LOGIN:
      logInfo(`[Route] Processing LOGIN callback: /${path}`);
      authenticator
        .handleLoginCallbackAsync()
        .then(() => bootstrap(authenticator, AppSettings))
        .catch((err) => logError(`[Route] LOGIN callback failed: ${err}`));
      break;

    case OidcEndpoints.RENEW:
      logInfo(`[Route] Processing SILENT RENEW callback: /${path}`);
      authenticator
        .handleSilentRenewCallbackAsync()
        .then(() => start())
        .catch(logError);
      break;

    case OidcEndpoints.LOGOUT:
      logInfo(`[Route] Processing LOGOUT: /${path}`);
      // Notify other tabs to log out.
      // This tab arrived here either via OIDC post-logout redirect or via the
      // cross-tab BroadcastChannel listener; in both cases we broadcast once more
      // so any remaining tabs also clean up.  The same-tab loop is prevented by
      // the pathname guard added to initializeCrossTabLogout().
      broadcastLogoutToOtherTabs();
      if (AppSettings.OIDC_ENABLED) {
        authenticator.logoutAsync().catch((err) => logError(`[Route] Logout failed: ${err}`));
      } else {
        // JWT mode: clear any stale tokens and redirect to the login page.
        clearAuthTokens();
        clearAuthUser();
        window.location.replace('/login');
      }
      break;

    default: {
      logInfo(`[Route] Default path: /${path} — running bootstrap`);
      // Capture /company/{code} before starting the microfrontend shell.
      // Web.Home reads `pending_company_code` on mount and resolves branding.
      if (/^company\/[A-Za-z0-9_-]+$/.test(path)) {
        const code = path.split('/')[1];
        localStorage.setItem('pending_company_code', code);
        logInfo(`[Route] Company code captured: ${code} — redirecting to /login`);
        window.history.replaceState(null, '', '/login');
      }
      bootstrap(authenticator, AppSettings);
      break;
    }
  }
} catch (error) {
  logError(`[Root Config] Fatal startup error: ${error}`);
}
