import legacyAliases from './legacy-mfe-aliases.json';

const ALIASES = legacyAliases as Record<string, string>;

/** Map deprecated import-map / route names → canonical single-spa package name. */
export function resolveMfeModuleName(name: string): string {
  return ALIASES[name] ?? name;
}

export function getLegacyMfeAliases(): Record<string, string> {
  return { ...ALIASES };
}
