import { getSecureItem, removeSecureItem, setSecureItem, type SecureStorageConfig } from './secureStorage';

const ACCESS_TOKEN_CONFIG: SecureStorageConfig = {
  storageKey: 'auth_token',
  version: 1,
  hashKey: 'auth.access',
};

const REFRESH_TOKEN_CONFIG: SecureStorageConfig = {
  storageKey: 'auth_refresh_token',
  version: 1,
  hashKey: 'auth.refresh',
};

const JWT_LIKE = /^[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+$/;

function isJwtLike(value: string): boolean {
  return JWT_LIKE.test(value.trim());
}

function readAccessToken(config: SecureStorageConfig): { value: string | null; valid: boolean } {
  const value = getSecureItem<string>(config, {
    allowLegacyPlain: true,
    legacyParse: (raw) => (isJwtLike(raw) ? raw : null),
  });
  return { value, valid: value != null };
}

function readRefreshToken(config: SecureStorageConfig): { value: string | null; valid: boolean } {
  const value = getSecureItem<string>(config, {
    allowLegacyPlain: true,
    legacyParse: (raw) => {
      const trimmed = raw.trim();
      return trimmed.length >= 32 ? trimmed : null;
    },
  });
  return { value, valid: value != null };
}

function readToken(
  config: SecureStorageConfig,
  kind: 'access' | 'refresh',
): { value: string | null; valid: boolean } {
  return kind === 'refresh' ? readRefreshToken(config) : readAccessToken(config);
}

function notifyAuthTokenChanged(token: string | null): void {
  window.dispatchEvent(new CustomEvent('linm:auth:token-changed', { detail: { token } }));
  window.dispatchEvent(new CustomEvent('linm:auth:changed'));
}

export function getAuthToken(): string | null {
  return readToken(ACCESS_TOKEN_CONFIG, 'access').value;
}

export function getAuthRefreshToken(): string | null {
  return readToken(REFRESH_TOKEN_CONFIG, 'refresh').value;
}

export interface SetAuthTokensInput {
  accessToken?: string | null;
  refreshToken?: string | null;
}

export function setAuthTokens(input: SetAuthTokensInput): void {
  const prevAccess = getAuthToken();
  const prevRefresh = getAuthRefreshToken();

  if (input.accessToken) {
    setSecureItem(ACCESS_TOKEN_CONFIG, input.accessToken);
  }
  if (input.refreshToken) {
    setSecureItem(REFRESH_TOKEN_CONFIG, input.refreshToken);
  }

  const nextAccess = getAuthToken();
  const nextRefresh = getAuthRefreshToken();
  if (prevAccess !== nextAccess || prevRefresh !== nextRefresh) {
    notifyAuthTokenChanged(nextAccess);
  }
}

export function hasValidAuthToken(): boolean {
  return readToken(ACCESS_TOKEN_CONFIG, 'access').valid;
}

export function clearAuthTokens(): void {
  removeSecureItem(ACCESS_TOKEN_CONFIG);
  removeSecureItem(REFRESH_TOKEN_CONFIG);
  notifyAuthTokenChanged(null);
}
