import {
  getSecureItem,
  removeSecureItem,
  type SecureStorageConfig,
} from '../storage/secureStorage';

export const ACTIVE_COMPANY_STORAGE_KEY = 'linm_active_company_id';

const CONFIG: SecureStorageConfig = {
  storageKey: ACTIVE_COMPANY_STORAGE_KEY,
  version: 1,
  hashKey: 'auth.activeCompany',
};

export function getActiveCompanyCode(): string | null {
  return getSecureItem<string>(CONFIG, { allowLegacyPlain: true });
}

export function clearActiveCompanyCode(): void {
  removeSecureItem(CONFIG);
}
