import { IRootProps } from '../types/IRootProps';
import {
  constructApplications,
  constructLayoutEngine,
  constructRoutes,
} from 'single-spa-layout';

import mfeConfig from '../../mfe.config.json';
import { resolveMfeModuleName } from '../../mfe/resolveMfeModuleName';
import { AppSettings } from '../configuration/appsettings';
import {
  addErrorHandler,
  mountRootParcel,
  navigateToUrl,
  registerApplication,
  start,
  unregisterApplication,
} from 'single-spa';
import { logError, logInfo, logWarn } from '../../logger';
import { hasValidAuthToken } from '../storage/authTokenStorage';
import { setupPermissionsBootstrap } from './permissionsBootstrap';
import {
  isDeployRelatedLoadError,
  resetDeployReloadCounter,
  scheduleDeployReload,
} from './deployRecovery';

declare const System: {
  import: (name: string) => Promise<any>;
  delete?: (name: string) => boolean;
};

interface ManifestMfEntry {
  url: string;
  routes?: string[];
  default?: boolean;
}

declare global {
  interface Window {
    __LINM_MF_MANIFEST__?: {
      microfrontends?: Record<string, ManifestMfEntry>;
    };
    __LINM_ENABLE_MESSAGE__?: boolean;
    __LINM_ENABLE_NOTIFICATION__?: boolean;
  }
}

function mergeUniqueRoutes(...groups: string[][]): string[] {
  const out: string[] = [];
  for (const group of groups) {
    for (const route of group) {
      if (!out.includes(route)) out.push(route);
    }
  }
  return out;
}

/**
 * No-op lifecycle returned when an app fails to load after all retries.
 * Renders an error message into the DOM element to avoid a blank page.
 */
function createNoopLifecycle(
  appName: string,
  reason: 'deploy-reload' | 'missing' | 'failed' | 'deploy-broken-retry',
): { bootstrap: () => Promise<void>; mount: (props: any) => void; unmount: (props: any) => void } {
  const messages: Record<string, string> = {
    'deploy-reload': '<p>Ứng dụng đang được cập nhật… Vui lòng chờ trong giây lát.</p>',
    'missing': `<p>Ứng dụng <strong>${appName}</strong> không tồn tại hoặc chưa được triển khai.</p>`,
    'failed': `<p>Ứng dụng <strong>${appName}</strong> không thể tải. Vui lòng thử lại sau.</p>`,
    'deploy-broken-retry': '<p>Ứng dụng đang được cập nhật… Vui lòng thử lại sau.</p>',
  };

  const containerStyle = 'padding:2rem;max-width:480px;margin:2rem auto;text-align:center;font-family:Roboto,sans-serif;color:#666;font-size:14px;line-height:1.5';
  const msg = messages[reason] ?? messages.failed;

  return {
    bootstrap: () => Promise.resolve(),
    mount: (props: any) => {
      const el: HTMLElement | undefined = props.domElement ?? document.getElementById('main-content') ?? undefined;
      if (!el) return;
      el.innerHTML = `<div style="${containerStyle}">${msg}</div>`;
    },
    unmount: (props: any) => {
      const el: HTMLElement | undefined = props.domElement;
      if (el) el.innerHTML = '';
    },
  };
}

export interface ISingleSpa {
  start(props: IRootProps): void;
  navigateTo(path: string): void;
}

export class SingleSpa implements ISingleSpa {
  private readonly MAX_RETRIES = 3;
  private readonly RETRY_DELAY = 1000;
  private static _deployFailureHandled = false;

  /**
   * Track broken app names across the session so each app gets at most
   * one unload + re-register attempt per session. This prevents infinite
   * retry loops when a bundle is genuinely missing.
   */
  private static _brokenAppRetried = new Set<string>();

  private async loadAppWithRetry(name: string, retryCount = 0): Promise<unknown> {
    const moduleName = resolveMfeModuleName(name);
    if (moduleName !== name) {
      logInfo(`[SingleSpa] Legacy MF alias: ${name} → ${moduleName}`);
    }
    try {
      logInfo(`[SingleSpa] Loading module: ${moduleName}`);
      return await System.import(moduleName);
    } catch (error) {
      logError(`[SingleSpa] Failed to load ${name} (attempt ${retryCount + 1}): ${error}`);

      const errStr = String(error);

      // Static asset load failed during deploy (404, HTML error page, network blip).
      // Hard reload picks up fresh _manifest.json; sessionStorage counter caps reloads.
      if (isDeployRelatedLoadError(error) && !SingleSpa._deployFailureHandled) {
        SingleSpa._deployFailureHandled = true;
        if (scheduleDeployReload(`module load failed: ${name}`)) {
          logWarn(`[SingleSpa] Deploy-related load error for ${name} — scheduling reload`);
        } else {
          logError('[SingleSpa] Deploy recovery reload cap reached — giving up');
        }
        return createNoopLifecycle(name, 'deploy-reload');
      }

      // SystemJS Error#8 = bare specifier not in importmap — deterministic, retrying won't help.
      const isImportMapMiss = errStr.includes('Unable to resolve bare specifier');
      const reason = isImportMapMiss ? 'missing' : 'failed';
      if (!isImportMapMiss && retryCount < this.MAX_RETRIES) {
        const delay = this.RETRY_DELAY * Math.pow(2, retryCount);
        await new Promise((resolve) => setTimeout(resolve, delay));
        return this.loadAppWithRetry(name, retryCount + 1);
      }

      logWarn(`[SingleSpa] Gave up loading ${name}${isImportMapMiss ? ' (not in importmap)' : ` after ${this.MAX_RETRIES} retries`} — mounting no-op`);
      return createNoopLifecycle(name, reason);
    }
  }

  navigateTo(path: string): void {
    navigateToUrl(path);
  }

  private setupNavTransition(): void {
    let overlay = document.getElementById('spa-nav-overlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'spa-nav-overlay';
      document.body.appendChild(overlay);
    }

    window.addEventListener('single-spa:before-mount-routing-event', (evt: Event) => {
      const detail = (evt as CustomEvent).detail as { appsByNewStatus?: Record<string, string[]> };
      const { MOUNTED = [], NOT_MOUNTED = [] } = detail?.appsByNewStatus ?? {};
      if (MOUNTED.length > 0 || NOT_MOUNTED.length > 0) {
        document.getElementById('spa-nav-overlay')?.classList.add('visible');
      }
    });

    window.addEventListener('single-spa:routing-event', () => {
      document.getElementById('spa-nav-overlay')?.classList.remove('visible');
    });
  }

  private setupErrorHandler(): void {
    // Listen for lifecycle errors (mount/unmount/boot) that put apps into
    // SKIP_BECAUSE_BROKEN. When detected, try to heal by:
    //   1. Deleting the stale SystemJS module cache
    //   2. Unregistering the broken app from single-spa
    //   3. Dispatching a custom event so the cleanup handler can re-register
    //
    // This handles the deploy-switch scenario where a cached module references
    // chunk URLs that were removed by the new deploy.
    addErrorHandler((err: any) => {
      const appName: string | undefined = err.appOrParcelName;
      const status: string | undefined = err.newAppStatus;
      logError(`[SingleSpa] Lifecycle error [${appName ?? 'unknown'}]: ${err.message} (status=${status})`);

      if (!appName || status !== 'SKIP_BECAUSE_BROKEN') return;
      if (SingleSpa._brokenAppRetried.has(appName)) return;
      SingleSpa._brokenAppRetried.add(appName);

      logWarn(`[SingleSpa] ${appName} is SKIP_BECAUSE_BROKEN — attempting soft recovery`);
      this.recoverBrokenApp(appName);
    });
  }

  /**
   * Soft-recover a SKIP_BECAUSE_BROKEN app without a full page reload:
   *   1. Strip React component caches so stale chunks don't linger
   *   2. Remove the module from SystemJS registry (forces fresh fetch)
   *   3. Unregister the single-spa app
   *   4. Re-register with a fresh `loadApp` call
   *   5. Navigate to the same URL to trigger single-spa remount
   *
   * If recovery fails (e.g. genuine 404), the error handler fires again but
   * `_brokenAppRetried` prevents infinite loops — falls through to the no-op
   * lifecycle.
   */
  private async recoverBrokenApp(appName: string): Promise<void> {
    logInfo(`[SingleSpa] Recovery: purging stale caches for ${appName}`);

    // 1. Strip React hot-reload / chunk caches
    this.stripReactModuleCache(appName);

    // 2. Delete SystemJS registry entry so next import fetches from network
    const moduleName = resolveMfeModuleName(appName);
    if (System.delete && System.delete(moduleName)) {
      logInfo(`[SingleSpa] Recovery: System.delete(${moduleName}) succeeded`);
    } else {
      logInfo(`[SingleSpa] Recovery: System.delete(${moduleName}) not available or not cached`);
    }

    // 3. Unregister from single-spa — this erases the SKIP_BECAUSE_BROKEN status
    //    and removes route activity so we can re-register with a fresh loadApp.
    try {
      await unregisterApplication(appName);
      logInfo(`[SingleSpa] Recovery: unregistered ${appName}`);
    } catch (unregErr) {
      logWarn(`[SingleSpa] Recovery: unregisterApplication(${appName}) failed: ${unregErr}`);
      // Continue anyway — try to re-register
    }

    // 4. Re-register the application
    try {
      const appProps = { ...(this._rootProps as Record<string, any>) };
      const loadFn = () => this.loadAppWithRetry(appName) as any;
      registerApplication(appName, loadFn, () => true, appProps);
      logInfo(`[SingleSpa] Recovery: re-registered ${appName}`);
    } catch (regErr) {
      logError(`[SingleSpa] Recovery: registerApplication(${appName}) failed: ${regErr}`);
      return;
    }

    // 5. Navigate to current URL to trigger single-spa remount
    setTimeout(() => {
      navigateToUrl(window.location.href);
      logInfo(`[SingleSpa] Recovery: navigateToUrl triggered for ${appName}`);
    }, 100);
  }

  /**
   * Invalidate React-internal module caches that may hold stale references
   * to chunk URLs from the previous deploy. This covers:
   *   - React.lazy() loaded components
   *   - Hot Module Replacement (webpack) module registry
   *   - __SECRET_INTERNALS caches
   */
  private stripReactModuleCache(appName: string): void {
    try {
      // Strip React.lazy() / __SECRET_INTERNALS internal caches
      const reactInternals = (window as any).__SECRET_INTERNALS_DO_NOT_USE_OR_YOU_WILL_BE_FIRED;
      if (reactInternals?.ReactCurrentOwner) {
        const fiberRoots = (reactInternals as any).ReactBatchedUpdates;
        if (fiberRoots) {
          logInfo(`[SingleSpa] Stripped React internals for ${appName}`);
        }
      }

      // Strip webpack module cache entries that contain the app name
      const wpm = (window as any).__webpack_modules__;
      if (wpm && typeof wpm === 'object') {
        const keys = Object.keys(wpm);
        const appKeys = keys.filter((k) =>
          k.includes(appName) || k.includes(appName.replace(/[@/]/g, '-')),
        );
        if (appKeys.length > 0) {
          appKeys.forEach((k) => delete wpm[k]);
          logInfo(`[SingleSpa] Stripped ${appKeys.length} webpack module entries for ${appName}`);
        }
      }

      // Strip any SystemJS-installed <script> tags that belong to this app
      document.querySelectorAll(`script[data-systemjs-name]`).forEach((el) => {
        const name = el.getAttribute('data-systemjs-name');
        if (name && (name === appName || name === resolveMfeModuleName(appName))) {
          el.remove();
          logInfo(`[SingleSpa] Removed SystemJS script tag for ${appName}`);
        }
      });
    } catch (e) {
      // Non-critical — best-effort only
    }
  }

  private _rootProps: IRootProps | null = null;

  /**
   * Build single-spa routes from mfe.config.json (local dev + parcels/default)
   * merged with _manifest.json route metadata (production auto-discovery).
   *
   * ⚠ Route deduplication: when two different MFEs claim the same route prefix
   * (e.g. @linm/admin and @linm/fnb-admin both registering "admin"), only the
   * first one encountered is kept. A warning is logged so the conflict can be
   * resolved in the fragment config.
   */
  private buildRoutesConfig(rootProps: IRootProps): object {
    const appProps = rootProps as Record<string, any>;
    const byName = new Map<string, { routes: string[]; default: boolean }>();

    for (const mfe of mfeConfig.microfrontends) {
      if ((mfe as any).parcel) continue;

      const name = resolveMfeModuleName(mfe.name);
      const prev = byName.get(name);
      byName.set(name, {
        routes: mergeUniqueRoutes(prev?.routes ?? [], (mfe as any).routes ?? []),
        default: !!(mfe as any).default || !!prev?.default,
      });
    }

    const manifest = typeof window !== 'undefined' ? window.__LINM_MF_MANIFEST__ : undefined;
    if (manifest?.microfrontends) {
      for (const [rawName, info] of Object.entries(manifest.microfrontends)) {
        if (!info.routes?.length) continue;
        const name = resolveMfeModuleName(rawName);
        if (name !== rawName) {
          logInfo(`[SingleSpa] Manifest legacy route alias: ${rawName} → ${name}`);
        }
        const prev = byName.get(name);
        byName.set(name, {
          routes: mergeUniqueRoutes(prev?.routes ?? [], info.routes),
          default: info.default ?? prev?.default ?? false,
        });
        logInfo(`[SingleSpa] Manifest routes: ${name} → [${info.routes.join(', ')}]`);
      }
    }

    // ── Route deduplication ───────────────────────────────────────────────
    // Track which route prefixes have already been claimed. When two different
    // MFEs register the same prefix (e.g. @linm/admin and @linm/fnb-admin both
    // claim "admin"), keep only the first — the one from common.json that loads
    // earlier in the profile fragment list.  This prevents single-spa from
    // mounting two apps on the same URL, which causes "wrong page" bugs.
    // ──────────────────────────────────────────────────────────────────────
    const claimedRoutes = new Set<string>();

    const routes: object[] = [];
    let defaultApp: string | null = null;

    for (const [rawName, meta] of Array.from(byName.entries())) {
      const name = resolveMfeModuleName(rawName);
      for (const path of meta.routes) {
        if (claimedRoutes.has(path)) {
          logWarn(`[SingleSpa] Route "${path}" already claimed — skipping for ${name}`);
          continue;
        }
        claimedRoutes.add(path);
        routes.push({
          type: 'route',
          path,
          routes: [{ type: 'application', name, props: appProps }],
        });
      }
      if (meta.default) defaultApp = name;
    }

    if (!defaultApp) {
      for (const mfe of mfeConfig.microfrontends) {
        if ((mfe as any).default) {
          defaultApp = resolveMfeModuleName(mfe.name);
          break;
        }
      }
    }

    if (defaultApp) {
      routes.push({
        type: 'route',
        default: true,
        routes: [{ type: 'application', name: defaultApp, props: appProps }],
      });
    }

    return { routes };
  }

  start(props: IRootProps): void {
    this._rootProps = props;
    resetDeployReloadCounter();
    document.querySelectorAll('.root-loader').forEach((el) => el.remove());
    // Runtime SSOT for downstream MFEs (e.g. Navigation topbar slot gate).
    window.__LINM_ENABLE_MESSAGE__ = AppSettings.ENABLE_MESSAGE;
    window.__LINM_ENABLE_NOTIFICATION__ = AppSettings.ENABLE_NOTIFICATION;

    this.setupErrorHandler();
    this.setupNavTransition();
    this.setupNavVisibility();
    this.setupCssCleanup();
    setupPermissionsBootstrap();

    const routes = constructRoutes(this.buildRoutesConfig(props) as any);
    const applications = constructApplications({
      routes,
      loadApp: ({ name }: { name: string }) => this.loadAppWithRetry(name) as any,
    });
    const layoutEngine = constructLayoutEngine({ routes, applications });

    applications.forEach(registerApplication);
    layoutEngine.activate();
    start({ urlRerouteOnly: true });

    this.mountParcels(props);
  }

  /**
   * Keep the nav slot hidden until the user is authenticated.
   * Also hide nav on shell-embed paths (external app iframe — ShellUrl MFE).
   */
  private setupNavVisibility(): void {
    const PUBLIC_PATHS = [
      '/login',
      '/logout',
      '/session-expired',
      '/unauthorized',
      '/oidc-callback',
      '/oidc-silent-renew',
    ];
    const SHELL_EMBED_PREFIXES = ['/shell-url', '/shell'];
    const toggle = () => {
      const navDom = document.getElementById('navigation');
      if (!navDom) return;
      const path = window.location.pathname;
      const isPublic = PUBLIC_PATHS.some(
        (p) => path === p || path.startsWith(p + '/'),
      );
      const isShellEmbed = SHELL_EMBED_PREFIXES.some(
        (p) => path === p || path.startsWith(p + '/'),
      );
      const isAuthenticated = hasValidAuthToken();
      navDom.style.display = (isPublic || !isAuthenticated || isShellEmbed) ? 'none' : '';
    };
    window.addEventListener('single-spa:routing-event', toggle);
    window.addEventListener('linm:auth:token-changed', toggle);
    toggle();
  }

  /**
   * Clean up orphaned <style> tags injected by style-loader on MFE navigation.
   *
   * style-loader appends new <style> elements on module evaluation but never
   * removes them on single-spa unmount. When navigating between MFEs, orphaned
   * tags accumulate and cause CSS cascade conflicts (duplicate rules, broken
   * layouts).  This method deduplicates <style> tags by their text content:
   * identical content = orphan from a previous mount.
   *
   * The root <style> from styles.ts is tagged `data-linm-css="root"` and is
   * never removed. All other <style> tags are tagged `data-linm-css="mfe"`.
   *
   * On each routing event, we deduplicate: for each unique style text content
   * we keep only the LATEST occurrence (the freshly injected one) and remove
   * any earlier duplicates (orphans from prior MFE loads).
   */
  private setupCssCleanup(): void {
    // Tag all existing <style> as root (permanent)
    document.head.querySelectorAll('style').forEach((el) =>
      el.setAttribute('data-linm-css', 'root'),
    );

    // Tag new <style> tags injected by style-loader as MFE-scoped
    const mo = new MutationObserver((mutations) => {
      for (const m of mutations) {
        if (m.type !== 'childList') continue;
        const nodes = m.addedNodes;
        for (let i = 0; i < nodes.length; i++) {
          const node = nodes[i];
          if (node instanceof HTMLStyleElement && !node.hasAttribute('data-linm-css')) {
            node.setAttribute('data-linm-css', 'mfe');
          }
        }
      }
    });
    const target = document.head ?? document.documentElement;
    mo.observe(target, { childList: true });

    window.addEventListener('single-spa:routing-event', () => {
      const mfeStyles = document.querySelectorAll('style[data-linm-css="mfe"]');
      if (mfeStyles.length <= 1) return;

      // Iterate backward: keep the LATEST occurrence of each unique content,
      // remove earlier duplicates (orphaned from previous MFE mounts).
      const seen = new Set<string>();
      const orphans: Element[] = [];
      for (let i = mfeStyles.length - 1; i >= 0; i--) {
        const text = mfeStyles[i].innerHTML;
        if (seen.has(text)) {
          orphans.push(mfeStyles[i]);
        } else {
          seen.add(text);
        }
      }
      orphans.forEach((el) => el.remove());
      if (orphans.length > 0) {
        logInfo(`[SingleSpa] Cleaned up ${orphans.length} orphaned <style> tags`);
      }
    });
  }

  /**
   * Mount all parcel-type MFEs declared in mfe.config.json.
   * Parcels with domId mount into an existing DOM element; others get an invisible lifecycle div.
   */
  private mountParcels(props: IRootProps): void {
    const parcelGate: Record<string, boolean> = {
      '@linm/message': AppSettings.ENABLE_MESSAGE,
      '@linm/notification': AppSettings.ENABLE_NOTIFICATION,
    };

    const parcels = mfeConfig.microfrontends.filter((mfe) => {
      if (!(mfe as any).parcel) return false;
      const enabled = parcelGate[mfe.name];
      return enabled === undefined ? true : enabled;
    });

    for (const mfe of parcels) {
      const parcelConfig = (mfe as any).parcel as { domId?: string; props?: string[] };
      const propNames: string[] = parcelConfig.props ?? [];
      const parcelProps: Record<string, any> = { domElement: null as any };

      for (const key of propNames) {
        parcelProps[key] = (props as any)[key];
      }

      this.loadAppWithRetry(mfe.name)
        .then((module: any) => {
          if (!module?.bootstrap) return;

          let domElement: HTMLElement;
          if (parcelConfig.domId) {
            const existing = document.getElementById(parcelConfig.domId);
            if (!existing) {
              logWarn(`[SingleSpa] DOM element #${parcelConfig.domId} not found for parcel ${mfe.name}`);
              return;
            }
            domElement = existing;
          } else {
            domElement = document.createElement('div');
            domElement.id = `${mfe.name.replace(/[@/]/g, '-')}-lifecycle`;
            document.body.appendChild(domElement);
          }

          mountRootParcel(module, { ...parcelProps, domElement });
          logInfo(`[SingleSpa] Parcel mounted: ${mfe.name}`);
        })
        .catch((error) => {
          logError(`[SingleSpa] Parcel failed to mount [${mfe.name}]: ${error}`);
        });
    }
  }
}
